// // This module implements a 4-bit shift register with parallel load.
// When load is low, the output is set to the value of the data input.
// On each falling edge of the clock, the output is shifted right by one bit.
module shift_register(
    input [3:0] d,
    input clk,
    input load,
    output reg [3:0] q
);

always @(posedge clk) begin
    if (load) begin
        q <= d;
    end else begin
        q <= {q[2:0], 1'b0};
    end
end

endmodule

